#include <zephyr/kernel.h>
#include <zephyr/device.h>
#include <zephyr/drivers/flash.h>
#include <zephyr/sys/printk.h>
#include <string.h>

#define STACK_SIZE      1024
#define ADMIN_PRIORITY  1
#define USER_PRIORITY   2

/* ----- Admin request definitions ---------------------------------------- */

typedef enum {
	ADMIN_REQ_FLASH_WRITE = 1,
	ADMIN_REQ_SET_CONFIG
} admin_op_t;

struct admin_request {
	admin_op_t op;
	union {
		struct {
			uint32_t addr;
			uint8_t  data[32];
			size_t   len;
		} flash;
		struct {
			uint32_t param;
			uint32_t value;
		} config;
	} u;
	k_tid_t requester;
};

K_MSGQ_DEFINE(admin_msgq, sizeof(struct admin_request), 10, 4);

/* ----- Simple system configuration -------------------------------------- */

static uint32_t system_config[8];

/* ----- Admin thread ----------------------------------------------------- */

static void admin_thread(void *p1, void *p2, void *p3)
{
	const struct device *flash_dev =
		device_get_binding(DT_CHOSEN_ZEPHYR_FLASH_CONTROLLER_LABEL);

	if (!flash_dev) {
		printk("Admin: flash device not found\n");
		return;
	}

	/* Mark this thread as admin for potential runtime checks */
	k_thread_custom_data_set((void *)1);

	struct admin_request req;

	for (;;) {
		k_msgq_get(&admin_msgq, &req, K_FOREVER);

		switch (req.op) {
		case ADMIN_REQ_FLASH_WRITE:
			printk("Admin: flash write by %p\n", req.requester);

			flash_write_protection_set(flash_dev, false);
			flash_write(flash_dev,
				    req.u.flash.addr,
				    req.u.flash.data,
				    req.u.flash.len);
			flash_write_protection_set(flash_dev, true);
			break;

		case ADMIN_REQ_SET_CONFIG:
			if (req.u.config.param < ARRAY_SIZE(system_config)) {
				system_config[req.u.config.param] = req.u.config.value;
				printk("Admin: config[%u] = %u by %p\n",
				       req.u.config.param,
				       req.u.config.value,
				       req.requester);
			}
			break;

		default:
			printk("Admin: unknown request\n");
			break;
		}
	}
}

/* ----- Privileged request APIs ----------------------------------------- */

static int request_admin_flash_write(uint32_t addr,
				     const uint8_t *data,
				     size_t len)
{
	if (!k_is_user_context()) {
		return -EPERM;
	}

	struct admin_request req = {
		.op        = ADMIN_REQ_FLASH_WRITE,
		.requester = k_current_get(),
	};

	req.u.flash.addr = addr;
	req.u.flash.len  = MIN(len, sizeof(req.u.flash.data));
	memcpy(req.u.flash.data, data, req.u.flash.len);

	return k_msgq_put(&admin_msgq, &req, K_FOREVER);
}

static int request_admin_set_config(uint32_t param, uint32_t value)
{
	if (!k_is_user_context()) {
		return -EPERM;
	}

	struct admin_request req = {
		.op        = ADMIN_REQ_SET_CONFIG,
		.requester = k_current_get(),
	};

	req.u.config.param = param;
	req.u.config.value = value;

	return k_msgq_put(&admin_msgq, &req, K_FOREVER);
}

/* ----- User thread ------------------------------------------------------ */

static void user_thread(void *p1, void *p2, void *p3)
{
	uint8_t sample_data[16];
	memset(sample_data, 0xAB, sizeof(sample_data));

	while (1) {
		printk("User: requesting flash write\n");
		request_admin_flash_write(0x00020000, sample_data, sizeof(sample_data));

		printk("User: requesting config change\n");
		request_admin_set_config(3, 42);

		k_sleep(K_SECONDS(5));
	}
}

/* ----- Thread & stack objects ------------------------------------------ */

K_THREAD_STACK_DEFINE(admin_stack, STACK_SIZE);
K_THREAD_STACK_DEFINE(user_stack,  STACK_SIZE);

static struct k_thread admin_tcb;
static struct k_thread user_tcb;

static k_tid_t admin_tid;
static k_tid_t user_tid;

/* ----- Main ------------------------------------------------------------- */

void main(void)
{
	admin_tid = k_thread_create(&admin_tcb,
				    admin_stack,
				    STACK_SIZE,
				    admin_thread,
				    NULL, NULL, NULL,
				    ADMIN_PRIORITY,
				    0,
				    K_NO_WAIT);

	user_tid  = k_thread_create(&user_tcb,
				    user_stack,
				    STACK_SIZE,
				    user_thread,
				    NULL, NULL, NULL,
				    USER_PRIORITY,
				    K_USER,
				    K_NO_WAIT);

	/* Grant user thread access to the admin message queue */
	k_object_access_grant(&admin_msgq, user_tid);

	printk("System: started (admin=%p user=%p)\n", admin_tid, user_tid);
}